As a workaround I butchered the vncserver script to hardcode the ip
address and display number, this seems to work (diff below). It looks like
the vncserver script can't correctly allocate these numbers.

rob@speeltuin:~>diff -u `which vncserver` bin/vncserver
--- /usr/local/bin/vncserver    2009-02-17 13:22:07.000000000 +1300
+++ bin/vncserver       2009-03-04 15:33:43.000000000 +1300
@@ -146,7 +146,7 @@
 } elsif ((@ARGV > 0) && ($ARGV[0] !~ /^-/)) {
     &Usage();
 } else {
-    $displayNumber = &GetDisplayNumber();
+    $displayNumber = 1;
 }

 $vncPort = 5900 + $displayNumber;
@@ -169,7 +169,7 @@

 # Now start the X VNC Server

-$cmd = "Xvnc :$displayNumber";
+$cmd = "Xvnc -interface 192.168.1.24 :$displayNumber";
 $cmd .= " -desktop " . &quotedString($desktopName);
 $cmd .= " -httpd $vncClasses";
 $cmd .= " -auth $xauthorityFile";
@@ -282,17 +282,17 @@
 # X server port (6000+n).
 #

-sub GetDisplayNumber
-{
-    foreach $n (1..99) {
-       if (&CheckDisplayNumber($n)) {
-           return $n+0; # Bruce Mah's workaround for bug in perl 5.005_02
-       }
-    }
-
-    die "$prog: no free display number on $host.\n";
-}
